const EmbeddedList = () => (
  <List<number>
    data={Array<number>(10)
      .fill(0)
      .map((_, i) => i)}
    itemKey={o => o}
    height={32 * 7.5}
  >
    {o => {
      switch (item) {
        default:
          return (
            <ListItem>
              <ListItemTitle>{`选项 ${o}`}</ListItemTitle>
            </ListItem>
          );
      }
    }}
  </List>
);

const TreeBefore = ({
  depth,
  isExpanded,
  isLeaf = false,
}: {
  depth: number;
  isLeaf?: boolean;
} & Pick<ExpandButtonProps, 'isExpanded'>) => (
  <>
    {Array(depth)
      .fill(0)
      .map((_, i) => (
        <span key={i} css={{ width: 16 }} />
      ))}
    <ExpandButton
      css={{
        margin: '3px 3px 3px 0',
      }}
      iconType="ExpandDownFilled"
      isExpanded={isExpanded}
      asPlaceholder={isLeaf}
    />
  </>
);

